insert into fuentes_externas (nombre, estado, notas) values
  ('Fincaraiz', 'pendiente', 'No hay API pública de autoservicio. Fincaraiz ofrece una API de partner (usada por softwares como Arrendasoft/Nuby) para PUBLICAR/sincronizar tu propio inventario hacia su portal, pero requiere ser cliente/aliado de Fincaraiz y que ellos entreguen una API key desde su panel (pestaña "Integraciones"). Sin esa key no hay endpoint ni documentación pública accesible. Alternativa de solo-lectura: servicios de terceros (PropAPIS, Apify) que hacen scraping de sus anuncios públicos — no permiten publicar, solo consultar, y su legalidad frente a los términos de Fincaraiz no está clara. Próximo paso: contactar al equipo comercial de Fincaraiz para solicitar acceso de partner y la API key.')
